<script setup lang="ts">
import{computed,ref}from'vue';import type{Customer,Recommendation}from'@/types/customer';import type{ActionStatus,CustomerResponse,RetentionAction,RetentionActionUpdate,RetentionOutcome}from'@/types/action';import{calculateOutcomeMetrics,isActionOverdue,latestActionForCustomer}from'@/utils/actionManager';import{potentialProtectableArr,realisedSavedArr}from'@/utils/revenueMetrics'
const props=defineProps<{customers:Customer[];recommendations:Recommendation[];actions:RetentionAction[]}>();const emit=defineEmits<{openCustomer:[number];openScenario:[number];createAction:[number];updateAction:[string,RetentionActionUpdate]}>()
const tab=ref<'queue'|'outcomes'>('queue'),owner=ref('All'),status=ref<'All'|ActionStatus>('All'),priority=ref('All'),outcome=ref<'All'|RetentionOutcome>('All');const customerMap=computed(()=>new Map(props.customers.map(c=>[c.id,c]))),metrics=computed(()=>calculateOutcomeMetrics(props.actions)),owners=computed(()=>['All',...new Set(props.actions.map(a=>a.owner))]);const statuses:ActionStatus[]=['Not started','Planned','In progress','Completed'],responses:CustomerResponse[]=['Pending','Accepted','Rejected','No response'],outcomes:RetentionOutcome[]=['Unknown','Retained','Downgraded','Churned']
const queue=computed(()=>props.recommendations.filter(r=>{const a=latestActionForCustomer(props.actions,r.customerId);return(owner.value==='All'||a?.owner===owner.value)&&(status.value==='All'||(a?.status??'Not started')===status.value)&&(priority.value==='All'||r.priority===priority.value)&&(outcome.value==='All'||(a?.outcome??'Unknown')===outcome.value)}).sort((a,b)=>b.priorityScore-a.priorityScore));const byType=computed(()=>{const map=new Map<string,{total:number;success:number;saved:number}>();props.actions.filter(a=>a.status==='Completed').forEach(a=>{const x=map.get(a.actionType)??{total:0,success:0,saved:0};x.total++;if(a.outcome==='Retained'||a.outcome==='Downgraded'){x.success++;x.saved+=a.realisedRevenueProtected}map.set(a.actionType,x)});return[...map.entries()]})
const money=(n:number)=>`RM ${Math.round(n).toLocaleString('en-MY')}`;const change=(id:string,key:keyof RetentionAction,e:Event)=>emit('updateAction',id,{[key]:(e.target as HTMLInputElement).value} as RetentionActionUpdate)
</script>
<template><div class="action-center page-stack"><section class="page-intro"><div><span class="eyebrow">Retention operations</span><h2>Action Center</h2><p>Create accountable interventions and record customer outcomes separately from workflow completion.</p></div><div class="tabs"><button :class="{active:tab==='queue'}" @click="tab='queue'">Active queue</button><button :class="{active:tab==='outcomes'}" @click="tab='outcomes'">Outcomes</button></div></section>
<template v-if="tab==='queue'"><section class="metrics"><article><span>Potential Protectable ARR</span><strong>{{money(potentialProtectableArr(customers,recommendations,actions))}}</strong><small class="formula-help" title="Specific non-monitor interventions for medium/high-risk customers, excluding rejected or churned actions.">Eligible intervention recommendations only</small></article><article><span>Realised Saved ARR</span><strong>{{money(realisedSavedArr(actions))}}</strong><small class="formula-help" title="Recorded realised revenue on completed actions whose outcome is Retained or Downgraded.">Recorded successful outcomes only</small></article><article><span>Overdue actions</span><strong>{{actions.filter(a=>isActionOverdue(a)).length}}</strong><small>Incomplete actions past due date</small></article></section>
<section class="filters"><label>Owner<select v-model="owner"><option v-for="x in owners" :key="x">{{x}}</option></select></label><label>Status<select v-model="status"><option>All</option><option v-for="x in statuses" :key="x">{{x}}</option></select></label><label>Priority<select v-model="priority"><option>All</option><option>Critical</option><option>High</option><option>Normal</option></select></label><label>Outcome<select v-model="outcome"><option>All</option><option v-for="x in outcomes" :key="x">{{x}}</option></select></label></section>
<section class="queue"><article v-for="r in queue" :key="r.customerId" class="action-card"><header><div><span class="priority">{{r.priority}} priority</span><h3>{{customerMap.get(r.customerId)?.companyName}}</h3><p>{{r.action}}</p></div><button v-if="!latestActionForCustomer(actions,r.customerId)" class="primary-button" @click="emit('createAction',r.customerId)">Create action</button><span v-else-if="isActionOverdue(latestActionForCustomer(actions,r.customerId)!)" class="overdue">Overdue</span></header><template v-for="action in [latestActionForCustomer(actions,r.customerId)]" :key="action?.id"><template v-if="action"><div class="editor-grid"><label>Owner<input :value="action.owner" @change="change(action.id,'owner',$event)"></label><label>Due date<input type="date" :value="action.dueDate" @change="change(action.id,'dueDate',$event)"></label><label>Status<select :value="action.status" @change="change(action.id,'status',$event)"><option v-for="x in statuses" :key="x">{{x}}</option></select></label><label>Customer response<select :value="action.customerResponse" @change="change(action.id,'customerResponse',$event)"><option v-for="x in responses" :key="x">{{x}}</option></select></label><label>Outcome<select :value="action.outcome" @change="change(action.id,'outcome',$event)"><option v-for="x in outcomes" :key="x">{{x}}</option></select></label><label>After risk<input type="number" min="0" max="100" :value="action.afterRisk" @change="emit('updateAction',action.id,{afterRisk:Number(($event.target as HTMLInputElement).value)})"></label><label>Realised protected revenue<input type="number" min="0" :value="action.realisedRevenueProtected" @change="emit('updateAction',action.id,{realisedRevenueProtected:Number(($event.target as HTMLInputElement).value)})"></label><label class="notes">Notes<textarea :value="action.notes" @change="change(action.id,'notes',$event)"></textarea></label></div><div class="action-footer"><span>Before risk {{action.beforeRisk}}%</span><span>{{action.status==='Completed'?'Workflow completed; outcome must still be recorded.':'Outcome remains pending until recorded.'}}</span><button v-if="action.status==='Completed'" @click="emit('updateAction',action.id,{status:'In progress'})">Reopen action</button><button @click="emit('openCustomer',r.customerId)">History & evidence</button><button @click="emit('openScenario',r.customerId)">Scenario</button></div><details v-if="actions.filter(a=>a.customerId===r.customerId).length>1"><summary>Past actions for this customer ({{actions.filter(a=>a.customerId===r.customerId).length-1}})</summary><p v-for="past in actions.filter(a=>a.customerId===r.customerId&&a.id!==action.id)" :key="past.id">{{past.createdAt.slice(0,10)}} · {{past.title}} · {{past.status}} · {{past.outcome}}</p></details></template></template></article></section></template>
<template v-else><section class="synthetic-note"><strong>Synthetic hackathon demonstration outcomes.</strong><span>Only records explicitly labelled synthetic are seeded; new actions remain pending.</span></section><section class="outcome-grid"><article><span>Customers retained</span><strong>{{metrics.retained}}</strong></article><article><span>Downgraded</span><strong>{{metrics.downgraded}}</strong></article><article><span>Churned</span><strong>{{metrics.churned}}</strong></article><article><span>Unknown / pending</span><strong>{{metrics.unknown}}</strong></article><article><span>Recorded saved ARR</span><strong>{{money(metrics.realisedSavedArr)}}</strong></article><article><span>Action success rate</span><strong>{{metrics.successRate===null?'Insufficient data':`${metrics.successRate}%`}}</strong></article><article><span>Average completion time</span><strong>{{metrics.averageCompletionDays===null?'Insufficient data':`${metrics.averageCompletionDays} days`}}</strong></article></section><section class="panel results"><h3>Results by action type</h3><div v-if="byType.length"><p v-for="[type,value] in byType" :key="type"><strong>{{type}}</strong><span>{{value.success}} successful of {{value.total}} · {{money(value.saved)}} saved ARR</span></p></div><div v-else class="empty">No completed outcomes have been recorded.</div></section><section class="panel results"><h3>Before-risk versus after-risk</h3><p v-for="a in actions.filter(x=>x.afterRisk!==undefined)" :key="a.id"><strong>{{customerMap.get(a.customerId)?.companyName}}</strong><span>{{a.beforeRisk}}% 鈫?{{a.afterRisk}}% · {{a.outcome}}</span></p><div v-if="!actions.some(a=>a.afterRisk!==undefined)" class="empty">Record an after-risk value to compare results.</div></section></template></div></template>
<style scoped>.action-center{max-width:1540px;margin:auto;padding:32px clamp(20px,3vw,48px) 56px}.page-intro{display:flex;align-items:end;justify-content:space-between;gap:24px}.tabs{display:flex;padding:5px;border-radius:999px;background:var(--color-mist)}.tabs button{padding:10px 18px;border:0;border-radius:999px;background:transparent}.tabs .active{color:#fff;background:#171717}.metrics,.outcome-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}.metrics article,.outcome-grid article{padding:20px;border:1px solid var(--color-border);border-radius:18px}.metrics span,.metrics strong,.metrics small,.outcome-grid span,.outcome-grid strong{display:block}.metrics strong,.outcome-grid strong{margin:6px 0;font:400 28px var(--font-display)}.filters,.editor-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.filters label,.editor-grid label{font-size:12px;font-weight:700}.filters select,.editor-grid input,.editor-grid select,.editor-grid textarea{display:block;width:100%;min-height:42px;margin-top:5px;padding:8px 10px;border:1px solid var(--color-border);border-radius:10px;background:#fff}.queue{display:grid;gap:14px}.action-card{padding:22px;border-radius:20px}.action-card header,.action-footer{display:flex;align-items:center;justify-content:space-between;gap:16px}.action-card h3{margin:5px 0;font:400 27px var(--font-display)}.action-card p{margin:0;color:var(--color-muted)}.priority,.overdue{font-size:12px;font-weight:800}.overdue{padding:6px 10px;border-radius:999px;color:var(--color-danger);background:var(--color-danger-soft)}.editor-grid{margin-top:20px}.notes{grid-column:span 2}.action-footer{margin-top:16px;padding-top:14px;border-top:1px solid var(--color-border);flex-wrap:wrap}.action-footer button{padding:8px 11px;border:1px solid var(--color-border);border-radius:10px;background:#fff}.synthetic-note{display:flex;gap:10px;padding:18px;border-radius:16px;color:var(--color-brown);background:var(--color-peach)}.outcome-grid{grid-template-columns:repeat(4,1fr)}.results{padding:24px;border-radius:20px}.results p{display:flex;justify-content:space-between;padding:12px 0;border-top:1px solid var(--color-border)}.empty{padding:30px;color:var(--color-muted);text-align:center}@media(max-width:900px){.page-intro{align-items:start;flex-direction:column}.metrics,.outcome-grid,.filters,.editor-grid{grid-template-columns:1fr 1fr}}@media(max-width:600px){.metrics,.outcome-grid,.filters,.editor-grid{grid-template-columns:1fr}.notes{grid-column:auto}.action-card header{align-items:start;flex-direction:column}.synthetic-note{flex-direction:column}}</style>
